import type { MutableRefObject } from 'react'
import type { UseEngagementReturn, VideoData } from './analytics.type'
import { useEngagement } from './useEngagement'
import { useSegmentTracking } from './useSegmentTracking'

export const useVideoAnalytics = (dataRef: MutableRefObject<VideoData>, trackingKey?: string): UseEngagementReturn => {
  useSegmentTracking(dataRef, trackingKey)
  const tracking = useEngagement(dataRef, trackingKey)
  return tracking
}
