import { useMemo } from 'react'
import { getPlayerConfig } from './helpers'
import { type CoreBrightcovePlayerProps } from '../types/BrightcovePlayer'

const noop = (): void => {
  /* No operation performed */
}

export const useConfig = (props: CoreBrightcovePlayerProps): ReturnType<typeof getPlayerConfig> => {
  const {
    videoId,
    accountId,
    onError = noop,
    onUnpause = noop,
    onPause = noop,
    onStart = noop,
    onEnd = noop,
    onMute = noop,
    onUnmute = noop,
    onLoop = noop,
    onReady = noop,
    autoplay = false,
    disableControls = false,
    muted = false,
    aspectRatio,
    loop = false,
    containerId,
  } = props

  const config = useMemo(
    () =>
      getPlayerConfig({
        accountId,
        videoId,
        containerId,
        aspectRatio,
        autoplay,
        muted,
        disableControls,
        loop,
        onEnd,
        onLoop,
        onPause,
        onStart,
        onError,
        onMute,
        onUnmute,
        onUnpause,
        onReady,
      }),
    [
      accountId,
      videoId,
      containerId,
      aspectRatio,
      autoplay,
      disableControls,
      muted,
      loop,
      onEnd,
      onLoop,
      onPause,
      onStart,
      onError,
      onMute,
      onUnmute,
      onUnpause,
      onReady,
    ]
  )

  return config
}
