import type { MutableRefObject } from 'react'
import { useEffect, useRef } from 'react'
import pauseable from 'pauseable'
import zionDebug from '@fs/zion-debug'
import { useEvent } from '@fs/zion-react-utils'

const debug = zionDebug('zion:use-timer')

type Timer = {
  pause(): void
  resume(): void
  clear(): void
}

type UseTimerApi = {
  startTimer(length: number, done: () => void): void
  pauseTimer(): void
  resumeTimer(): void
  resetTimer(): void
  timerRef: MutableRefObject<Timer | null>
}

export default function useTimer(): UseTimerApi {
  const timerRef = useRef<Timer | null>(null)

  useEffect(() => {
    return () => {
      timerRef.current?.clear()
    }
  }, [])

  const startTimer = useEvent((length: number, done: () => void): void => {
    debug('start')
    timerRef.current = pauseable.setTimeout(() => {
      done()
    }, length)
  })
  const pauseTimer = useEvent((): void => {
    debug('pause')
    timerRef.current?.pause()
  })
  const resumeTimer = useEvent((): void => {
    debug('resume')
    timerRef.current?.resume()
  })
  const resetTimer = useEvent((): void => {
    debug('stop')
    timerRef.current?.clear()
  })

  return { startTimer, pauseTimer, resumeTimer, resetTimer, timerRef }
}
