import React, { useCallback, useState, forwardRef } from 'react'
import { Skeleton } from '@fs/zion-ui'
import { buildPlayer } from '../../utils/helpers'
import { useBitmovinScript } from '../../utils/useBitmovinScript'
import type { CoreBrightcovePlayerProps } from '../../types/BrightcovePlayer'
import { usePlayerMounting } from '../../utils/usePlayerMounting'
import { useConfig } from '../../utils/useConfig'

export const CoreBrightcovePlayer = forwardRef(
  (
    { title, containerId, contentLocale, aspectRatio = '16 / 9', disableControls, ...props }: CoreBrightcovePlayerProps,
    ref: React.ForwardedRef<HTMLDivElement>
  ): JSX.Element => {
    const [loading, setLoading] = useState(true)
    const config = useConfig({
      containerId,
      aspectRatio,
      ...props,
    })

    const onLoad = useCallback(async () => {
      await buildPlayer(config, contentLocale)
      const controlBar = window.bitmovin[containerId]?.getContainer()?.querySelector('.bmpui-ui-controlbar')
      if (controlBar) {
        if (disableControls) {
          controlBar.style.display = 'none'
        } else {
          controlBar.style.display = 'block'
        }
      }
      setLoading(false)
    }, [config, containerId, contentLocale, disableControls])

    const onScriptError = useCallback((event) => {
      console.error(`The script ${(event.target as HTMLScriptElement).src} didn't load correctly.`)
    }, [])
    const scriptReady = useBitmovinScript({ onError: onScriptError })
    usePlayerMounting(containerId, onLoad, scriptReady)

    return (
      <>
        {loading && (
          <div style={{ aspectRatio }}>
            <Skeleton.Image width="100%" height="100%" />
          </div>
        )}
        <div
          ref={ref}
          aria-label={title}
          style={{ aspectRatio, display: loading ? 'none' : 'inherit' }}
          id={containerId}
          data-testid="video-player"
        />
      </>
    )
  }
)
