import { useState, useEffect, useCallback } from 'react'

const BITMOVIN_SCRIPT = 'https://pbs-streaming-dist.churchofjesuschrist.org/bitmovin-player.min.js'

export const useBitmovinScript = ({ onError }): boolean => {
  const [scriptReady, setScriptReady] = useState(() => !!globalThis.bitmovin)

  const onScriptLoad = useCallback(() => {
    setScriptReady(true)
  }, [])

  useEffect(() => {
    // Script already loaded (e.g. from a previous mount)
    if (globalThis.bitmovin) {
      setScriptReady(true)
      return undefined
    }

    let script = document.querySelector<HTMLScriptElement>(`script[src="${BITMOVIN_SCRIPT}"]`)

    if (script) {
      // Script tag exists but hasn't finished loading yet
      const existingScript = script
      existingScript.addEventListener('load', onScriptLoad)
      existingScript.addEventListener('error', onError)

      return () => {
        existingScript.removeEventListener('load', onScriptLoad)
        existingScript.removeEventListener('error', onError)
      }
    }

    script = document.createElement('script')
    script.src = BITMOVIN_SCRIPT
    script.async = true
    script.addEventListener('load', onScriptLoad)
    script.addEventListener('error', onError)
    document.head.appendChild(script)

    return () => {
      script.removeEventListener('load', onScriptLoad)
      script.removeEventListener('error', onError)
    }
  }, [onScriptLoad, onError])

  return scriptReady
}
