export type VideoPlayer = 'youtube' | 'brightcove'

export type VideoBase = {
  id: string
  name: string
  videoPlayer: VideoPlayer
}

export type TimeArgs = {
  currentTime: number
  duration: number
}

export type VideoData = VideoBase & {
  getCurrentTime: () => number
  getIsLive: () => boolean
  duration: number
}

export type SegmentTrackingBase = TimeArgs &
  VideoBase & {
    isLive: boolean
  }

export type SegmentTrackingData = Omit<SegmentTrackingBase, 'currentTime' | 'isLive'> & {
  currentTime: number | undefined
  isLive: boolean | undefined
}

export type Milestone = 0 | 0.25 | 0.5 | 0.75 | 1

export type ProgressArgs = TimeArgs &
  VideoBase & {
    milestonesReached: Record<Milestone, boolean>
    isLive: boolean
  }

export type TrackingParams = {
  segmentName: string
  eventName: string
  isLive: boolean
} & VideoBase

export type TrackingData = {
  event_name: string
  video_id: string
  video_player: VideoPlayer
  video_name: string
  video_segment_name: string
  video_live: boolean
}

export type UseEngagementReturn = {
  pauseEngagement: () => void
  resumeEngagement: () => void
  trackEngagement: () => void
}

export const createDefaultVideoData = (videoPlayer: VideoPlayer): VideoData => ({
  getCurrentTime: () => 0,
  getIsLive: () => false,
  duration: -1,
  id: '',
  name: '',
  videoPlayer,
})
