import { type MutableRefObject, useEffect } from 'react'
import zionDebug from '@fs/zion-debug'
import { checkProgress } from './analytics'
import { type ProgressArgs, type SegmentTrackingBase, type SegmentTrackingData, type VideoData } from './analytics.type'

const debug = zionDebug('zion:video')

const SECOND = 1000
const WAIT_FOR_DATA_REF_CHECK = 100

const getTrackingData = (dataRef: MutableRefObject<VideoData>): SegmentTrackingData => {
  const { duration, id, name, videoPlayer } = dataRef.current || {}
  const currentTime = dataRef.current?.getCurrentTime?.()
  const isLive = dataRef.current?.getIsLive?.()

  return { currentTime, isLive, duration, id, name, videoPlayer }
}

const hasRequiredTrackingData = (data: SegmentTrackingData): data is SegmentTrackingBase => {
  return !(
    Object.values(data).some((value) => value == null) ||
    !data.id ||
    !data.name ||
    (data.duration != null && data.duration < 0)
  )
}

export const useSegmentTracking = (dataRef: MutableRefObject<VideoData>, trackingKey?: string): void => {
  // NOTE: start tracking immediately because if we use state to start tracking, it updates other parts and causes a headache
  useEffect(() => {
    const milestonesReached = {} as ProgressArgs['milestonesReached']
    let trackingInterval: ReturnType<typeof setInterval> | undefined
    let waitForDataRefInterval: ReturnType<typeof setInterval> | undefined

    const clearTrackingInterval = (): void => {
      if (trackingInterval) {
        clearInterval(trackingInterval)
        trackingInterval = undefined
      }
    }

    const clearWaitForDataRefInterval = (): void => {
      if (waitForDataRefInterval) {
        clearInterval(waitForDataRefInterval)
        waitForDataRefInterval = undefined
      }
    }

    const trackCurrentProgress = (): void => {
      const data = getTrackingData(dataRef)
      if (!hasRequiredTrackingData(data)) {
        debug('Checking progress for analytics milestones but missing required data', { data })
        return
      }

      const isFinished = checkProgress({
        ...data,
        // NOTE: pass in the milestones reached so that we can reset the milestones when the component is unmounted
        milestonesReached,
      })

      if (isFinished) {
        debug('stopping interval to track segments because we are finished')
        clearTrackingInterval()
      }
    }

    const startTrackingInterval = (): void => {
      debug('starting interval to track segments')
      trackingInterval = setInterval(() => {
        try {
          trackCurrentProgress()
        } catch (error) {
          // pass through the error so that sentry can track it
          console.error(error)
          debug(
            "stopping interval because something happened that we weren't expecting",
            error instanceof Error ? error.message : String(error)
          )
          // exit gracefully
          clearTrackingInterval()
        }
      }, SECOND)
    }

    if (!trackingKey || dataRef.current?.id === trackingKey) {
      startTrackingInterval()
    } else {
      debug('waiting for analytics dataRef to update before tracking segments', {
        trackingKey,
        id: dataRef.current?.id,
      })
      waitForDataRefInterval = setInterval(() => {
        if (dataRef.current?.id !== trackingKey) {
          return
        }
        clearWaitForDataRefInterval()
        startTrackingInterval()
      }, WAIT_FOR_DATA_REF_CHECK)
    }

    return () => {
      clearWaitForDataRefInterval()
      debug('stopping interval to track segments because we un-mounted')
      clearTrackingInterval()
    }
  }, [dataRef, trackingKey])
}
