// exported or testing
export const langConversions = {
  ar: 'ara',
  da: 'dan',
  de: 'deu',
  en: 'eng',
  es: 'spa',
  fj: 'fij',
  fr: 'fra',
  hu: 'hun',
  id: 'ind',
  it: 'ita',
  ja: 'jpn',
  km: 'khm',
  ko: 'kor',
  mn: 'mon',
  nl: 'nld',
  no: 'nor',
  pt: 'por',
  ru: 'rus',
  sm: 'smo',
  th: 'tha',
  tl: 'tgl',
  to: 'ton',
  vi: 'vie',
  zh: 'zho',

  'zh-HK': 'yue',
  ceb: 'ceb',
}

/**
 * Converts a language code to a Brightcove language code
 * @param code The language code to convert
 * @returns The converted language code
 */
export const getConvertedCode = (code?: string): string => {
  const fallback = langConversions.en
  if (!code) {
    return fallback
  }
  if (Object.values(langConversions).includes(code)) {
    return code
  }

  if (langConversions[code]) {
    return langConversions[code]
  }
  const baseCode = code.split('-')[0]
  return langConversions[baseCode] ?? fallback
}
