import type { onBitmovinReadyProps } from '../../../../types/BrightcovePlayer'

export const onBitmovinReady = ({ player, start, ref }: onBitmovinReadyProps): void => {
  if (start) {
    player.seek(start)
  }

  const pauseButton = ref.current?.querySelector('[aria-label="Pause"]') as HTMLElement | null
  pauseButton?.focus()
}
