import { trackVideo } from '@fs/zion-analytics'
import type { Milestone, ProgressArgs, TimeArgs, TrackingData, TrackingParams } from './analytics.type'

const nearEndSeconds = 10

const eventNames: Record<Milestone, string> = {
  0: 'video_play',
  0.25: '25',
  0.5: '50',
  0.75: '75',
  1: 'video_complete',
}

// these fields are defined in the FamilySearch data layer. https://docs.google.com/spreadsheets/d/1VsfZTzsI4nQre8qt5WbKVBK9M7EwEExvmMcf_-j8bSQ/edit?gid=366884203#gid=366884203
const segmentNames: Record<Milestone, string> = {
  0: 'video_play',
  0.25: 'video_segment',
  0.5: 'video_segment',
  0.75: 'video_segment',
  1: 'video_complete',
}

const sendTracking = ({ segmentName, eventName, id, name, videoPlayer, isLive }: TrackingParams): void => {
  const trackingData: TrackingData = {
    event_name: eventName,
    video_id: id,
    video_player: videoPlayer,
    video_name: name,
    video_segment_name: segmentName,
    video_live: isLive,
  }
  trackVideo(trackingData)
}

const determinePotentialMilestone = ({ currentTime, duration }: TimeArgs): Milestone | null => {
  if (duration <= 0 || currentTime === 0) return null

  const milestoneSeconds: [number, Milestone | null][] = [
    [0, 0],
    [duration * 0.25, 0.25],
    [duration * 0.5, 0.5],
    [duration * 0.75, 0.75],
    [duration - nearEndSeconds, 1],
    // This is necessary to allow the current time to fall between the last valid segment and the actual end of the video
    [duration, null],
  ]
  // sort so that we can get the milestones in order if completed happens before 75; do it separately to satisfy types
  milestoneSeconds.sort(([a], [b]) => a - b)

  const currentMilestoneKey = milestoneSeconds.findIndex((m, index) => {
    return currentTime >= m[0] && currentTime < milestoneSeconds[index + 1]?.[0]
  })
  const milestone = currentMilestoneKey > -1 ? milestoneSeconds[currentMilestoneKey][1] : null

  return milestone
}

export const checkProgress = ({
  currentTime,
  isLive,
  duration,
  id,
  name,
  milestonesReached,
  videoPlayer,
}: ProgressArgs): boolean => {
  if (currentTime >= duration) return true

  const milestone = determinePotentialMilestone({ currentTime, duration })
  if (milestone === null) return false
  if (!milestonesReached[milestone]) {
    milestonesReached[milestone] = true
    sendTracking({
      segmentName: segmentNames[milestone],
      eventName: eventNames[milestone],
      id,
      name,
      videoPlayer,
      isLive,
    })
  }
  return Object.keys(eventNames)
    .map(Number)
    .every((m) => milestonesReached[m])
}
