import zionDebug from '@fs/zion-debug'
import type { PlayerConfig } from '../types/bitmovin'
import { getConvertedCode } from './languageHelpers'

const debug = zionDebug('zion:video')

const LANG_PARAM_KEY = 'lang'

export const getPlayerConfig = ({
  accountId,
  videoId,
  containerId,
  aspectRatio,
  autoplay,
  disableControls,
  muted,
  loop,
  onEnd,
  onLoop,
  onPause,
  onStart,
  onError,
  onMute,
  onUnmute,
  onUnpause,
  onReady,
}): PlayerConfig => {
  // NOTE: we reference the window object directly because we need to pass the player object before it has been built. After it has been built, the events will fire and that object should be be defined
  return {
    dataAccount: accountId,
    dataVideoId: videoId,
    disableControls,
    containerId,
    cast: { enable: true },
    remotecontrol: { type: 'googlecast' },
    style: { aspectratio: aspectRatio },
    playback: {
      autoplay,
      muted,
      blockDownloads: true,
    },
    events: {
      playbackfinished: {
        function: () => {
          onEnd(window.bitmovin[containerId])
          if (loop) {
            onLoop()
            window.bitmovin[containerId].play()
          }
        },
      },
      paused: {
        function: () => onPause(window.bitmovin[containerId]),
      },
      ready: {
        function: () => onReady(window.bitmovin[containerId]),
      },
      play: {
        function: () => onStart(window.bitmovin[containerId]),
      },
      error: { function: onError },
      muted: { function: onMute },
      unmuted: { function: onUnmute },
      playing: { function: onUnpause },
    },
  }
}

// NOTE: we are using the window object directly because we did not want to post a navigation event when updating the url; It also makes it easier to use outside of react
export const buildPlayer = async (config, contentLocale): Promise<void> => {
  const currentUrl = new URL(window.location.href)
  // store the original lang parameter from the browser URL if it exists
  const originalLang = currentUrl.searchParams.get(LANG_PARAM_KEY)
  const langCode = getConvertedCode(contentLocale)
  currentUrl.searchParams.set(LANG_PARAM_KEY, langCode)
  window.history.replaceState({}, '', currentUrl.toString())

  try {
    debug('building the player with lang', langCode)
    await globalThis.bitmovin.buildPlayer(config)
  } catch (error) {
    console.error('There was a problem building the Brightcove Player')
    throw error
  } finally {
    if (originalLang) {
      currentUrl.searchParams.set(LANG_PARAM_KEY, originalLang)
    } else {
      currentUrl.searchParams.delete(LANG_PARAM_KEY)
    }
    window.history.replaceState({}, '', currentUrl.toString())
  }
}
