import React, { useRef, useMemo, useCallback } from 'react'
import { type VideoData, createDefaultVideoData } from '../../../../utils/analytics/analytics.type'
import { CoreBrightcovePlayer } from '../../../components'
import { type BrightcovePlayerProps } from '../../../types/BrightcovePlayer'
import { onBitmovinReady } from './utils/handlers'
import { type Player } from '../../../types/bitmovin'
import { useVideoAnalytics } from '../../../../utils/analytics/useVideoAnalytics'

const noop = (): void => {
  /* No operation performed */
}

// handle all logic that is not directly tied to the BC player, like tracking analytics
export const BrightcovePlayer = ({
  videoId,
  accountId,
  onUnpause = noop,
  onPause = noop,
  start = 0,
  ...props
}: BrightcovePlayerProps): JSX.Element => {
  // We want to check for this before we even start downloading the script
  useMemo(() => {
    if (!accountId || !videoId) {
      throw new Error('BrightcovePlayer: accountId and videoId are required')
    }
  }, [accountId, videoId])

  const ref = useRef<HTMLDivElement>(null)
  const containerId = `bitmovin-player-${accountId.trim()}-${videoId.trim()}`
  const dataRef = useRef<VideoData>(createDefaultVideoData('brightcove'))
  const { pauseEngagement, resumeEngagement, trackEngagement } = useVideoAnalytics(dataRef, videoId)

  const onPlayerPause = useCallback(
    (e: Player): void => {
      pauseEngagement()
      onPause(e)
    },
    [pauseEngagement, onPause]
  )

  const onReady = useCallback((): void => {
    // wrap getCurrentTime so the player instance is used as the receiver. This ensures internal player state is available when the function is called elsewhere
    const getCurrentTime = (): number => window.bitmovin[containerId]?.getCurrentTime?.() ?? 0
    const getIsLive = (): boolean => window.bitmovin[containerId]?.isLive?.() ?? false
    const duration = window.bitmovin[containerId].getDuration()
    const id = window.bitmovin[containerId].getInfo()?.dataVideoId
    const name = window.bitmovin[containerId].getSource()?.title
    dataRef.current = { getCurrentTime, getIsLive, duration, id, name, videoPlayer: 'brightcove' }

    trackEngagement()
    onBitmovinReady({ player: window.bitmovin[containerId], start, ref })
  }, [trackEngagement, containerId, start, ref])

  const onPlayerUnpause = useCallback((): void => {
    resumeEngagement()
    onUnpause()
  }, [resumeEngagement, onUnpause])

  return (
    <CoreBrightcovePlayer
      onPause={onPlayerPause}
      onReady={onReady}
      onUnpause={onPlayerUnpause}
      ref={ref}
      containerId={containerId}
      accountId={accountId}
      videoId={videoId}
      {...props}
    />
  )
}
