import { useEffect, useRef } from 'react'
import zionDebug from '@fs/zion-debug'

const debug = zionDebug('zion:video')

/**
 * Manages the mounting and unmounting of a Bitmovin player.
 */
export const usePlayerMounting = (containerId, onLoad, scriptReady): void => {
  const buildingRef = useRef(false)

  useEffect(() => {
    let cancelled = false

    if (scriptReady && !globalThis.bitmovin?.[containerId] && !buildingRef.current) {
      buildingRef.current = true
      debug('loading the player')
      onLoad().finally(() => {
        buildingRef.current = false
        if (cancelled) {
          debug('player build completed after cleanup — skipping')
        }
      })
    }
    return () => {
      cancelled = true
      const player = globalThis.bitmovin?.[containerId]
      if (player) {
        const sourceTitle = player.getSource?.()?.title
        debug('destroying the player', sourceTitle)
        player.destroy()
        if (globalThis.bitmovin?.[containerId] === player) {
          delete globalThis.bitmovin[containerId]
        }
      }
    }
  }, [containerId, onLoad, scriptReady])
}
