import { useCallback, useEffect, useRef } from 'react'
import type { MutableRefObject } from 'react'
import { useTimer } from '@fs/zion-frontend-friends'
import { trackEvent } from '@fs/zion-analytics'
import zionDebug from '@fs/zion-debug'
import { type VideoData, type UseEngagementReturn } from './analytics.type'

const debug = zionDebug('zion:video')

const SECOND = 1000

type EngagementMilestone = {
  seconds: number
  eventName: string
}

const ENGAGEMENT_MILESTONES: EngagementMilestone[] = [
  { seconds: 5, eventName: '5-seconds-watched' },
  { seconds: 10, eventName: '10-seconds-watched' },
  { seconds: 30, eventName: '30-seconds-watched' },
]

export const useEngagement = (
  dataRef: MutableRefObject<Pick<VideoData, 'id'>>,
  trackingKey?: string
): UseEngagementReturn => {
  const { startTimer, pauseTimer, resumeTimer, resetTimer } = useTimer()
  const nextMilestoneIndexRef = useRef(0)
  const currentSessionRef = useRef(0)
  const isTrackingRef = useRef(false)
  const isMountedRef = useRef(true)

  const stopTracking = useCallback((): void => {
    isTrackingRef.current = false
    nextMilestoneIndexRef.current = 0
    resetTimer()
  }, [resetTimer])

  const trackEngagement = useCallback((): void => {
    if (!isMountedRef.current || isTrackingRef.current) {
      return
    }

    isTrackingRef.current = true
    resetTimer()
    const sessionAtStart = currentSessionRef.current

    const onThresholdReached = (): void => {
      if (!isMountedRef.current || currentSessionRef.current !== sessionAtStart) {
        return
      }

      const currentMilestone = ENGAGEMENT_MILESTONES[nextMilestoneIndexRef.current]
      if (!currentMilestone) {
        stopTracking()
        return
      }

      trackEvent({
        video_id: dataRef.current.id,
        event_name: currentMilestone.eventName,
      })

      nextMilestoneIndexRef.current++

      const nextMilestone = ENGAGEMENT_MILESTONES[nextMilestoneIndexRef.current]
      if (!nextMilestone) {
        stopTracking()
        return
      }

      const timeUntilNextMilestone = (nextMilestone.seconds - currentMilestone.seconds) * SECOND
      startTimer(timeUntilNextMilestone, onThresholdReached)
    }

    const firstMilestone = ENGAGEMENT_MILESTONES[0]
    if (!firstMilestone) {
      stopTracking()
      return
    }

    startTimer(firstMilestone.seconds * SECOND, onThresholdReached)
  }, [startTimer, dataRef, resetTimer, stopTracking])

  useEffect(() => {
    isMountedRef.current = true
    return () => {
      debug('stopping engagement tracking because tracking key changed or player un-mounted')
      isMountedRef.current = false
      currentSessionRef.current += 1
      pauseTimer()
      stopTracking()
    }
  }, [trackingKey, pauseTimer, stopTracking])

  return { pauseEngagement: pauseTimer, resumeEngagement: resumeTimer, trackEngagement }
}
